// ---------------------------------------------------------------------------
// Fixtures
// ---------------------------------------------------------------------------

function makeLedgerEntry(overrides: Partial<LedgerEntry> = {}): LedgerEntry {
  return {
    ts: '2026-03-29T10:00:00Z',
    agent: 'test-generator',
    stage: 1,
    duration_ms: 10000,
    success: true,
    summary: 'Generated 47 tests',
    commit_base: 'abc123',
    ...overrides,
  };
}

// ---------------------------------------------------------------------------
// normalizeAgentName — BUG FIX #3 (double ork: prefix)
// ---------------------------------------------------------------------------

describe('normalizeAgentName', () => {
  test('strips ork: prefix', () => {
    expect(normalizeAgentName('ork:security-auditor')).toBe('security-auditor');
  });

  test('leaves plain agent name unchanged', () => {
    expect(normalizeAgentName('Explore')).toBe('Explore');
  });

  test('only strips first ork: prefix', () => {
    expect(normalizeAgentName('ork:ork:double')).toBe('ork:double');
  });

  test('handles empty string', () => {
    expect(normalizeAgentName('')).toBe('');
  });
});

// ---------------------------------------------------------------------------
// sanitizeBranch — BUG FIX #5 (allowlist-based)
// ---------------------------------------------------------------------------

describe('sanitizeBranch', () => {
  test('normal branch: slashes to double-dash', () => {
    expect(sanitizeBranch('feat/foo')).toBe('feat--foo');
  });

  test('nested branch', () => {
    expect(sanitizeBranch('feat/auth/oauth')).toBe('feat--auth--oauth');
  });

  test('strips path traversal sequences', () => {
    expect(sanitizeBranch('../../etc/passwd')).toBe('_--_--etc--passwd');
  });

  test('strips null bytes', () => {
    expect(sanitizeBranch('feat\x00bar')).toBe('feat_bar');
  });

  test('strips backslashes', () => {
    expect(sanitizeBranch('feat\\bar')).toBe('feat_bar');
  });

  test('strips colons', () => {
    expect(sanitizeBranch('feat:bar')).toBe('feat_bar');
  });

  test('strips shell-dangerous characters', () => {
    expect(sanitizeBranch('feat/$HOME/`whoami`')).toBe('feat--_HOME--_whoami_');
  });

  test('preserves dots and hyphens', () => {
    expect(sanitizeBranch('v1.2.3-rc.1')).toBe('v1.2.3-rc.1');
  });

  test('handles empty string', () => {
    expect(sanitizeBranch('')).toBe('');
  });

  test('branch with literal double-dash preserved', () => {
    expect(sanitizeBranch('my--branch')).toBe('my--branch');
  });
});

// ---------------------------------------------------------------------------
// formatDuration
// ---------------------------------------------------------------------------

describe('formatDuration', () => {
  test('zero', () => expect(formatDuration(0)).toBe('0m00s'));
  test('seconds only', () => expect(formatDuration(5000)).toBe('0m05s'));
  test('minutes and seconds', () => expect(formatDuration(121000)).toBe('2m01s'));
  test('rounds to nearest second', () => expect(formatDuration(5500)).toBe('0m06s'));
});

// ---------------------------------------------------------------------------
// readBranchLedger
// ---------------------------------------------------------------------------

describe('readBranchLedger', () => {
  const tmpDir = join(tmpdir(), `attribution-test-${process.pid}`);
  const activityDir = join(tmpDir, '.claude', 'agents', 'activity');

  beforeEach(() => {
    mkdirSync(activityDir, { recursive: true });
    // Mock getProjectDir by setting env
    process.env.CLAUDE_PROJECT_DIR = tmpDir;
  });

  afterEach(() => {
    rmSync(tmpDir, { recursive: true, force: true });
    delete process.env.CLAUDE_PROJECT_DIR;
  });

  test('returns empty array when file missing', () => {
    expect(readBranchLedger('nonexistent')).toEqual([]);
  });

  test('returns empty array for empty file', () => {
    writeFileSync(join(activityDir, 'test-branch.jsonl'), '');
    expect(readBranchLedger('test-branch')).toEqual([]);
  });

  test('parses valid JSONL', () => {
    const entry = makeLedgerEntry();
    writeFileSync(join(activityDir, 'test-branch.jsonl'), `${JSON.stringify(entry)}\n`);
    const result = readBranchLedger('test-branch');
    expect(result).toHaveLength(1);
    expect(result[0].agent).toBe('test-generator');
  });

  test('skips corrupt lines and returns valid ones', () => {
    const valid = makeLedgerEntry();
    const content = [
      JSON.stringify(valid),
      'NOT VALID JSON',
      JSON.stringify(makeLedgerEntry({ agent: 'Explore' })),
    ].join('\n');
    writeFileSync(join(activityDir, 'test-branch.jsonl'), content);
    const result = readBranchLedger('test-branch');
    expect(result).toHaveLength(2);
  });

  test('skips entries missing required fields', () => {
    const content = [
      JSON.stringify({ agent: 'valid', ts: '2026-01-01' }), // valid (minimal)
      JSON.stringify({ foo: 'bar' }),  // missing agent + ts
      JSON.stringify({ agent: 'also-valid', ts: '2026-01-02' }),
    ].join('\n');
    writeFileSync(join(activityDir, 'test-branch.jsonl'), content);
    const result = readBranchLedger('test-branch');
    expect(result).toHaveLength(2);
  });
});

// ---------------------------------------------------------------------------
// filterByThreshold — BUG FIX #4
// ---------------------------------------------------------------------------

describe('filterByThreshold', () => {
  test('filters by duration only — success is irrelevant', () => {
    const entries = [
      makeLedgerEntry({ duration_ms: 3000, success: true }),  // below threshold, success
      makeLedgerEntry({ duration_ms: 6000, success: false }), // above threshold, failed
    ];
    const result = filterByThreshold(entries);
    // Should keep ONLY the 6000ms one — success doesn't matter
    expect(result).toHaveLength(1);
    expect(result[0].duration_ms).toBe(6000);
  });

  test('custom threshold', () => {
    const entries = [
      makeLedgerEntry({ duration_ms: 1000 }),
      makeLedgerEntry({ duration_ms: 2000 }),
      makeLedgerEntry({ duration_ms: 3000 }),
    ];
    expect(filterByThreshold(entries, 2000)).toHaveLength(2);
  });

  test('empty entries', () => {
    expect(filterByThreshold([])).toEqual([]);
  });
});

// ---------------------------------------------------------------------------
// deduplicateAgents
// ---------------------------------------------------------------------------

describe('deduplicateAgents', () => {
  test('keeps longest-duration entry per agent', () => {
    const entries = [
      makeLedgerEntry({ agent: 'security-auditor', duration_ms: 5000 }),
      makeLedgerEntry({ agent: 'security-auditor', duration_ms: 12000 }),
      makeLedgerEntry({ agent: 'test-generator', duration_ms: 8000 }),
    ];
    const result = deduplicateAgents(entries);
    expect(result).toHaveLength(2);
    expect(result.find(e => e.agent === 'security-auditor')!.duration_ms).toBe(12000);
  });

  test('preserves single entries', () => {
    const entries = [makeLedgerEntry({ agent: 'Explore' })];
    expect(deduplicateAgents(entries)).toHaveLength(1);
  });

  test('empty entries', () => {
    expect(deduplicateAgents([])).toEqual([]);
  });
});

// ---------------------------------------------------------------------------
// formatAsTrailers — BUG FIX #3 (no double ork: prefix)
// ---------------------------------------------------------------------------

describe('formatAsTrailers', () => {
  test('produces correct Co-Authored-By format', () => {
    const entries = [makeLedgerEntry({ agent: 'security-auditor' })];
    const result = formatAsTrailers(entries);
    expect(result).toBe('Co-Authored-By: ork:security-auditor <noreply@orchestkit.dev>');
  });

  test('NO double ork: prefix when agent already has ork: prefix', () => {
    const entries = [makeLedgerEntry({ agent: 'ork:security-auditor' })];
    const result = formatAsTrailers(entries);
    // MUST be ork:security-auditor, NOT ork:ork:security-auditor
    expect(result).toBe('Co-Authored-By: ork:security-auditor <noreply@orchestkit.dev>');
    expect(result).not.toContain('ork:ork:');
  });

  test('multiple agents', () => {
    const entries = [
      makeLedgerEntry({ agent: 'ork:backend-system-architect', duration_ms: 5000 }),
      makeLedgerEntry({ agent: 'Explore', duration_ms: 3000 }),
    ];
    const result = formatAsTrailers(entries);
    expect(result).toContain('ork:backend-system-architect');
    expect(result).toContain('ork:Explore');
    expect(result.split('\n')).toHaveLength(2);
  });

  test('empty entries', () => {
    expect(formatAsTrailers([])).toBe('');
  });
});

